import json
import hashlib
import time
from collections import defaultdict
from dataclasses import dataclass, field

# --- Infrastructure ---
class DeduplicationRing:
    def __init__(self):
        self._hashes = set()
    def content_hash(self, r):
        return hashlib.sha256(json.dumps(r, sort_keys=True).encode()).hexdigest()
    def is_duplicate(self, r):
        return self.content_hash(r) in self._hashes
    def mark_processed(self, r):
        self._hashes.add(self.content_hash(r))
    def deduplicate_batch(self, records):
        unique, skipped = [], 0
        for r in records:
            if self.is_duplicate(r): skipped += 1
            else: unique.append(r)
        return unique, skipped
    def __len__(self):
        return len(self._hashes)

@dataclass
class PhaseResult:
    phase_name: str
    items: list
    errors: list = field(default_factory=list)

# --- Input data (with duplicates) ---
records = [
    {"id": "V-1", "name": "Pfizer Inc"},
    {"id": "V-2", "name": "Roche AG"},
    {"id": "V-1", "name": "Pfizer Inc"},
    {"id": "V-3", "name": "Unknown Corp"},
    {"id": "V-4", "name": "Novartis Pharma"},
    {"id": "V-2", "name": "Roche AG"}
]

entities = [
    {"id": "E-10", "name": "Pfizer Inc."},
    {"id": "E-20", "name": "Roche Holding AG"},
    {"id": "E-30", "name": "Novartis AG"}
]
symbol_table = "\n".join(f"  {e['id']}: {e['name']}" for e in entities)

# --- Phase 0: Dedup ---
dedup = DeduplicationRing()
unique, skipped = dedup.deduplicate_batch(records)
for r in unique:
    dedup.mark_processed(r)
print(f"[DEDUP] {skipped} duplicates skipped, {len(unique)} to process")

# --- Phase 1: Triage ---
prompts = [
    f"Triage record against entities. Return JSON: {{record_id, disposition (exact_match|fuzzy_match|anomaly), confidence, matched_entity_id (null if none)}}.\nEntities: {symbol_table}\nRecord: {json.dumps(r)}"
    for r in unique
]
raw = llm_query_batched(prompts)

decisions = []
errors = []
for r, resp in zip(unique, raw):
    try:
        obj = json.loads(resp.strip())
        decisions.append(obj)
    except Exception as e:
        errors.append({"record_id": r["id"], "error": str(e)})

# --- Phase 2: Route ---
buckets = defaultdict(list)
for d in decisions:
    buckets[d["disposition"]].append(d)

results = {}
for disp, items in buckets.items():
    results[disp] = PhaseResult(disp, items)
if errors:
    results["_errors"] = PhaseResult("errors", [], errors=errors)

print(f"Triage: {len(decisions)} decisions, {len(errors)} errors")
for disp, pr in results.items():
    print(f"  {disp}: {len(pr.items)} items, {len(pr.errors)} errors")
pipeline_errors = errors
pipeline_decisions = decisions
